 1	import * as React from 'react';
 2	import Helmet from 'react-helmet';
 3	import { useTranslation } from 'react-i18next';
 4	import { Page, PageSection, Title } from '@patternfly/react-core';
 5	import { useLocation } from 'react-router-dom';
 6	import './kuadrant.css';
 7	import AssociatedResourceList from './AssociatedResourceList';
 8	import {
 9	  useK8sWatchResources,
10	  K8sResourceCommon,
11	  useActiveNamespace,
12	} from '@openshift-console/dynamic-plugin-sdk';
13	
14	import extractResourceNameFromURL from '../utils/nameFromPath';
15	
16	const GatewayPoliciesPage: React.FC = () => {
17	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
18	  const [activeNamespace] = useActiveNamespace();
19	  const location = useLocation();
20	
21	  const routeName = extractResourceNameFromURL(location.pathname);
22	  const resources = {
23	    gateway: {
24	      groupVersionKind: {
25	        group: 'gateway.networking.k8s.io',
26	        version: 'v1',
27	        kind: 'Gateway',
28	      },
29	      namespace: activeNamespace,
30	      name: routeName,
31	      isList: false,
32	    },
33	  };
34	
35	  const watchedResources = useK8sWatchResources<{ gateway: K8sResourceCommon }>(resources);
36	  const { loaded, loadError, data: httpRoute } = watchedResources.gateway;
37	
38	  return (
39	    <>
40	      <Helmet>
41	        <title data-test="example-page-title">{t('Kuadrant Policies')}</title>
42	      </Helmet>
43	      <Page>
44	        <PageSection variant="light">
45	          <Title headingLevel="h2">{t('Kuadrant Policies')}</Title>
46	          {!loaded ? (
47	            <div>Loading...</div>
48	          ) : loadError ? (
49	            <div>Error loading HTTPRoute: {loadError.message}</div>
50	          ) : (
51	            <AssociatedResourceList resource={httpRoute} />
52	          )}
53	        </PageSection>
54	      </Page>
55	    </>
56	  );
57	};
58	
59	export default GatewayPoliciesPage;

